Steps:
[AUTH role=ORG_USER]
[GQL-OP list_all]
  query {
    currentCustomerAddresses(first: 5) {
      totalCount
      items { id city countryCode line1 postalCode }
    }
  }
[GQL-EXEC list_all]
[GQL-CAPTURE list_all.data.currentCustomerAddresses.items.0.id → ADDR_ID]
[GQL-OP filter_by_id]
  query {
    currentCustomerAddresses(first: 5, id: "{{ADDR_ID}}") {
      totalCount
      items { id city countryCode line1 postalCode }
    }
  }
[GQL-EXEC filter_by_id]

[AUTH role=ORG_USER]
[GQL-OP no_match]
  query {
    currentCustomerAddresses(first: 5, id: "00000000-0000-0000-0000-000000000000") {
      totalCount
      items { id }
    }
  }
[GQL-EXEC no_match]

[AUTH role=ORG_USER]
[GQL-OP list_nofilter]
  query {
    currentCustomerAddresses(first: 20) {
      totalCount
      items { id city countryCode line1 postalCode regionId isDefault isFavorite addressType }
    }
  }
[GQL-EXEC list_nofilter]

[GQL-OP desc_sort]
  query {
    newsArticles(
      storeId: "{{STORE_ID}}"
      languageCode: "en-US"
      sort: "publishDate:desc"
      first: 5
    ) {
      totalCount
      items { id title publishDate }
    }
  }
[GQL-EXEC desc_sort]

[GQL-OP asc_sort]
  query {
    newsArticles(
      storeId: "{{STORE_ID}}"
      languageCode: "en-US"
      sort: "publishDate:asc"
      first: 5
    ) {
      totalCount
      items { id title publishDate }
    }
  }
[GQL-EXEC asc_sort]

[GQL-OP nosort]
  query {
    newsArticles(
      storeId: "{{STORE_ID}}"
      languageCode: "en-US"
      first: 5
    ) {
      totalCount
      items { id title publishDate }
    }
  }
[GQL-EXEC nosort]

[GQL-OP list_pages_health]
  query {
    pages(storeId: "{{STORE_ID}}" keyword: "" first: 5 cultureName: "en-US") {
      totalCount
      items { id name relativeUrl permalink }
    }
  }
[GQL-EXEC list_pages_health]

[GQL-OP list_pages_seed]
  query {
    pages(storeId: "{{STORE_ID}}" keyword: "" first: 1 cultureName: "en-US") {
      items { id name }
    }
  }
[GQL-EXEC list_pages_seed]
[GQL-CAPTURE list_pages_seed.data.pages.items.0.id → CAPTURED_PAGE_ID]
[GQL-OP one_page_post_reindex]
  query {
    page(storeId: "{{STORE_ID}}" id: "{{CAPTURED_PAGE_ID}}" cultureName: "en-US") {
      id name relativeUrl permalink
    }
  }
[GQL-EXEC one_page_post_reindex]

[GQL-OP builder_probe]
  query {
    builderPage(storeId: "{{STORE_ID}}" pageId: "00000000-0000-0000-0000-000000000000") {
      id content
    }
  }
[GQL-EXEC builder_probe]

[GQL-OP products_term_facets]
  query {
    products(
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      first: 1
      filter: "category.subtree:9238c387-d779-40cb-b27d-5496a670a924"
      facet: "Brand"
    ) {
      totalCount
      term_facets { name label facetType terms { term label count isSelected } }
    }
  }
[GQL-EXEC products_term_facets]

[GQL-OP products_range_facets]
  query {
    products(
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      first: 1
      filter: "category.subtree:9238c387-d779-40cb-b27d-5496a670a924"
      facet: "price.USD"
    ) {
      totalCount
      range_facets { name label facetType ranges { count from to fromStr toStr label isSelected } }
    }
  }
[GQL-EXEC products_range_facets]
